// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const db = new Database("data.db");

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  created_at: string;
  updated_at: string;
};

app.use(express.json());

db.exec(`
  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  )
`);

const getBookmarkById = (id: number): Bookmark | undefined => {
  return db
    .prepare("SELECT id, url, title, description, created_at, updated_at FROM bookmarks WHERE id = ?")
    .get(id) as Bookmark | undefined;
};

const parseBookmarkId = (rawId: string): number | null => {
  const id = Number(rawId);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const readRequiredString = (value: unknown): string | null => {
  if (typeof value !== "string") {
    return null;
  }

  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const readOptionalDescription = (value: unknown): string | null => {
  if (value === undefined || value === null) {
    return null;
  }

  return typeof value === "string" ? value : String(value);
};

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/bookmarks", (req, res) => {
  const url = readRequiredString(req.body?.url);
  const title = readRequiredString(req.body?.title);

  if (!url) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!title) {
    return res.status(400).json({ error: "title is required" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      "INSERT INTO bookmarks (url, title, description, created_at, updated_at) VALUES (?, ?, ?, ?, ?)",
    )
    .run(url, title, readOptionalDescription(req.body?.description), now, now);

  const bookmark = getBookmarkById(Number(result.lastInsertRowid));
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (_req, res) => {
  const bookmarks = db
    .prepare("SELECT id, url, title, description, created_at, updated_at FROM bookmarks ORDER BY id ASC")
    .all() as Bookmark[];

  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const bookmark = getBookmarkById(id);
  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const existing = getBookmarkById(id);
  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const url = req.body?.url === undefined ? existing.url : readRequiredString(req.body.url);
  const title = req.body?.title === undefined ? existing.title : readRequiredString(req.body.title);

  if (!url) {
    return res.status(400).json({ error: "url must be non-empty" });
  }

  if (!title) {
    return res.status(400).json({ error: "title must be non-empty" });
  }

  const description =
    req.body?.description === undefined ? existing.description : readOptionalDescription(req.body.description);
  const updatedAt = new Date().toISOString();

  db.prepare("UPDATE bookmarks SET url = ?, title = ?, description = ?, updated_at = ? WHERE id = ?").run(
    url,
    title,
    description,
    updatedAt,
    id,
  );

  return res.status(200).json(getBookmarkById(id));
});

app.delete("/bookmarks/:id", (req, res) => {
  const id = parseBookmarkId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const result = db.prepare("DELETE FROM bookmarks WHERE id = ?").run(id);
  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;

