// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import express from "express";
import Database from "better-sqlite3";

const app = express();
const PORT = Number(process.env.PORT) || 3000;
const db = new Database("data.db");

type Bookmark = {
  id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type FolderWithBookmarks = Folder & {
  bookmarks: Bookmark[];
};

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (folder_id) REFERENCES folders(id) ON DELETE SET NULL
  )
`);

const bookmarkColumns = db.prepare("PRAGMA table_info(bookmarks)").all() as Array<{ name: string }>;
if (!bookmarkColumns.some((column) => column.name === "folder_id")) {
  db.prepare("ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL").run();
}

const getBookmarkById = (id: number): Bookmark | undefined => {
  return db
    .prepare("SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE id = ?")
    .get(id) as Bookmark | undefined;
};

const getFolderById = (id: number): Folder | undefined => {
  return db.prepare("SELECT id, name, created_at, updated_at FROM folders WHERE id = ?").get(id) as
    | Folder
    | undefined;
};

const getBookmarksByFolderId = (folderId: number): Bookmark[] => {
  return db
    .prepare(
      "SELECT id, url, title, description, folder_id, created_at, updated_at FROM bookmarks WHERE folder_id = ? ORDER BY id ASC",
    )
    .all(folderId) as Bookmark[];
};

const parsePositiveId = (rawId: string): number | null => {
  const id = Number(rawId);
  return Number.isInteger(id) && id > 0 ? id : null;
};

const readRequiredString = (value: unknown): string | null => {
  if (typeof value !== "string") {
    return null;
  }

  const trimmed = value.trim();
  return trimmed.length > 0 ? trimmed : null;
};

const readOptionalDescription = (value: unknown): string | null => {
  if (value === undefined || value === null) {
    return null;
  }

  return typeof value === "string" ? value : String(value);
};

const readOptionalFolderId = (value: unknown): number | null | undefined => {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  const folderId = typeof value === "number" ? value : Number(value);
  return Number.isInteger(folderId) && folderId > 0 ? folderId : undefined;
};

const resolveFolderId = (value: unknown): { ok: true; folderId: number | null } | { ok: false } => {
  const folderId = readOptionalFolderId(value);

  if (folderId === undefined) {
    return { ok: false };
  }

  if (folderId !== null && !getFolderById(folderId)) {
    return { ok: false };
  }

  return { ok: true, folderId };
};

