  res.status(200).json({ status: "ok" });
});

app.post("/folders", (req, res) => {
  const name = readRequiredString(req.body?.name);

  if (!name) {
    return res.status(400).json({ error: "name is required" });
  }

  const now = new Date().toISOString();
  const result = db.prepare("INSERT INTO folders (name, created_at, updated_at) VALUES (?, ?, ?)").run(name, now, now);
  const folder = getFolderById(Number(result.lastInsertRowid));

  return res.status(201).json(folder);
});

app.get("/folders", (_req, res) => {
  const folders = db.prepare("SELECT id, name, created_at, updated_at FROM folders ORDER BY id ASC").all() as Folder[];
  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const id = parsePositiveId(req.params.id);
  if (!id) {
    return res.status(404).json({ error: "folder not found" });
  }

  const folder = getFolderById(id);
  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  const response: FolderWithBookmarks = {
    ...folder,
    bookmarks: getBookmarksByFolderId(id),
  };

  return res.status(200).json(response);
});

